
import React, { useEffect, useMemo, useState } from "react";
import { createRoot } from "react-dom/client";
import { createClient } from "@supabase/supabase-js";
import { Home, Plus, FileText, Search, ShieldCheck, Send, Printer, RefreshCw, Euro, Wrench, Users, Car, Cpu, KeyRound, Trash2, Save, AlertTriangle } from "lucide-react";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "./config.js";
import "./styles.css";

const LOGO = "data:image/jpeg;base64,";
const supabaseReady = SUPABASE_URL && SUPABASE_ANON_KEY && !SUPABASE_ANON_KEY.includes("PEGA_AQUI");
const supabase = supabaseReady ? createClient(SUPABASE_URL, SUPABASE_ANON_KEY) : null;

const SERVICES = ["Diagnóstico","Reparación electrónica","Clonación","Virginización","Programación","Codificación","Adaptación","Lectura EEPROM","Lectura FLASH","Lectura MCU / MPC","Bench","Boot","OBD","Recuperación de datos","Transferencia de datos","Actualización software","Downgrade software","Duplicado de llaves","Programación de llaves","All Keys Lost","Reparación inmovilizador","Sincronización ECU / IMMO","Extracción PIN","Extracción CS","Extracción ISN","Immo Off","ELV / ESL","EZS / EIS","CAS","FEM / BDC","BCM","BSI","UCH","FRM","Gateway","ECU Motor","TCU / Caja automática","Cuadro de instrumentos","Airbag","ABS / ESP","EPS","Módulo columna dirección","Módulos confort","Reparación sistema Airbag","Reparación sistema IMMO","Reparación bloqueo electrónico de dirección","Clonación unidades usadas","Configuración módulos nuevos","Stage 1","Stage 2","Stage 3","Pops & Bangs","Hard Cut","Launch Control","VMAX Off","DPF Off","EGR Off","AdBlue Off","OPF / GPF Off","Swirl Flaps Off","Start/Stop Off","Catalizador Off","Desactivación DTC","Ajuste caja automática","Calibración personalizada"];
const STATUS = ["Recibido", "En diagnóstico", "En reparación", "Esperando material", "Pendiente cliente", "Finalizado", "Enviado", "Garantía"];
const PAYMENTS = ["Pendiente", "Efectivo", "Transferencia", "Tarjeta", "Bizum"];

function today() { return new Date().toISOString().slice(0, 10); }
function money(n) { return Number(n || 0); }
function totalIncome(o) { return money(o.income_service) + money(o.income_transport) + money(o.income_extra) - money(o.discount); }
function totalExpenses(o) { return money(o.expense_parts) + money(o.expense_module) + money(o.expense_transport) + money(o.expense_material) + money(o.expense_labor) + money(o.expense_other); }
function profit(o) { return totalIncome(o) - totalExpenses(o); }

function makeNextOT(orders) {
  const year = new Date().getFullYear();
  const nums = orders.map(o => o.ot_number || "").filter(id => id.startsWith(`OT-${year}-`)).map(id => parseInt(id.split("-").pop(), 10)).filter(Boolean);
  const next = nums.length ? Math.max(...nums) + 1 : 1;
  return `OT-${year}-${String(next).padStart(6, "0")}`;
}

function emptyOrder(nextNumber) {
  return {
    ot_number: nextNumber, date_in: today(), date_out: "", status: "Recibido",
    client_name: "", client_phone: "", client_email: "", client_type: "Particular",
    vehicle_brand: "", vehicle_model: "", vehicle_plate: "", vehicle_vin: "", vehicle_year: "",
    module_type: "", module_ref: "", module_serial: "", module_source: "Aportado por cliente",
    services: [], service_manual: "", unit_manual: "",
    fault_description: "", diagnosis: "", work_done: "", replaced_parts: "", tests_done: "", internal_notes: "", client_notes: "",
    technician_main: "", technician_aux: "", reviewed_by: "",
    income_service: 0, income_transport: 0, income_extra: 0, discount: 0,
    expense_parts: 0, expense_module: 0, expense_transport: 0, expense_material: 0, expense_labor: 0, expense_other: 0,
    payment_method: "Pendiente", paid: false, tracking_in: "", tracking_out: "", warranty_applies: true, warranty_notes: ""
  };
}

function App() {
  const [orders, setOrders] = useState([]);
  const [view, setView] = useState("dashboard");
  const [selected, setSelected] = useState(null);
  const [query, setQuery] = useState("");
  const [error, setError] = useState("");
  const [ok, setOk] = useState("");
  const [loading, setLoading] = useState(false);

  async function loadOrders() {
    setError(""); setOk("");
    if (!supabaseReady) return setError("Falta configurar Supabase en src/config.js. Pega tu ANON PUBLIC KEY.");
    setLoading(true);
    const { data, error } = await supabase.from("orders").select("*").order("created_at", { ascending: false });
    setLoading(false);
    if (error) return setError(error.message);
    setOrders(data || []);
    if (!selected && data?.[0]) setSelected(data[0]);
  }

  useEffect(() => { loadOrders(); }, []);

  async function createOrder() {
    const order = emptyOrder(makeNextOT(orders));
    if (!supabaseReady) { setSelected(order); setView("editor"); return; }
    const { data, error } = await supabase.from("orders").insert(order).select().single();
    if (error) return setError(error.message);
    setSelected(data); setView("editor"); setOk("OT creada correctamente."); await loadOrders();
  }

  async function saveOrder(order) {
    setError(""); setOk("");
    if (!supabaseReady) return setError("Configura Supabase antes de guardar.");
    const { data, error } = await supabase.from("orders").upsert({ ...order, updated_at: new Date().toISOString() }).select().single();
    if (error) return setError(error.message);
    setSelected(data); setOk("OT guardada y sincronizada."); await loadOrders();
  }

  async function deleteOrder(order) {
    if (!order?.id || !confirm("¿Eliminar esta OT?")) return;
    const { error } = await supabase.from("orders").delete().eq("id", order.id);
    if (error) return setError(error.message);
    setSelected(null); setView("orders"); await loadOrders();
  }

  const filtered = useMemo(() => {
    const q = query.toLowerCase().trim();
    if (!q) return orders;
    return orders.filter(o => [o.ot_number,o.client_name,o.client_phone,o.client_email,o.vehicle_plate,o.vehicle_vin,o.module_type,o.module_ref,o.status,o.technician_main].some(v => String(v || "").toLowerCase().includes(q)));
  }, [orders, query]);

  return <div className="app">
    <aside className="sidebar no-print">
      <div className="brand">{LOGO ? <img src={LOGO} /> : <div className="ak">AK</div>}<div><h1>Autokeys SAT V3.1</h1><p>Supabase</p></div></div>
      <button onClick={() => setView("dashboard")}><Home size={18}/> Panel</button>
      <button onClick={createOrder}><Plus size={18}/> Nueva OT</button>
      <button onClick={() => setView("orders")}><FileText size={18}/> Órdenes</button>
      <button onClick={() => setView("finance")}><Euro size={18}/> Gastos / Beneficios</button>
      <button onClick={() => setView("clientCopy")} disabled={!selected}><Printer size={18}/> Copia cliente</button>
      <button onClick={() => setView("warranty")} disabled={!selected}><ShieldCheck size={18}/> Garantía GAR-001</button>
      <button onClick={loadOrders}><RefreshCw size={18}/> Sincronizar</button>
      <div className="contact">Tel/WhatsApp: 632 982 646<br/>info@autokeyspro.es</div>
    </aside>
    <main>
      {error && <div className="alert"><AlertTriangle size={18}/>{error}</div>}
      {ok && <div className="success">{ok}</div>}
      {loading && <div className="success">Cargando datos...</div>}
      {view === "dashboard" && <Dashboard orders={orders} createOrder={createOrder} setView={setView}/>}
      {view === "orders" && <Orders orders={filtered} query={query} setQuery={setQuery} setSelected={setSelected} setView={setView}/>}
      {view === "editor" && selected && <Editor order={selected} setSelected={setSelected} saveOrder={saveOrder} deleteOrder={deleteOrder} setView={setView}/>}
      {view === "finance" && <Finance orders={orders} setSelected={setSelected} setView={setView}/>}
      {view === "clientCopy" && selected && <ClientCopy order={selected}/>}
      {view === "warranty" && selected && <Warranty order={selected}/>}
    </main>
  </div>;
}

function Dashboard({ orders, createOrder, setView }) {
  const count = s => orders.filter(o => o.status === s).length;
  const income = orders.reduce((a,o)=>a+totalIncome(o),0);
  const expenses = orders.reduce((a,o)=>a+totalExpenses(o),0);
  return <section><div className="head no-print"><h2>Panel principal</h2><button className="red" onClick={createOrder}>Crear nueva OT</button></div>
    <div className="cards"><Card label="Total OT" value={orders.length}/><Card label="En reparación" value={count("En reparación")}/><Card label="Facturación" value={income.toFixed(2)+" €"}/><Card label="Beneficio" value={(income-expenses).toFixed(2)+" €"}/></div>
    <div className="panel"><h3>Últimas órdenes</h3>{orders.slice(0,8).map(o => <div className="row" key={o.id}><b>{o.ot_number}</b><span>{o.client_name || "Sin cliente"}</span><span>{o.module_type || "Sin módulo"}</span><span>{o.technician_main || "Sin técnico"}</span><span className="pill">{o.status}</span></div>)}<button className="red" onClick={() => setView("orders")}>Ver órdenes</button></div>
  </section>;
}
function Card({ label, value }) { return <div className="card"><span>{label}</span><strong>{value}</strong></div>; }
function Orders({ orders, query, setQuery, setSelected, setView }) {
  return <section><h2>Órdenes</h2><div className="search no-print"><Search size={18}/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar OT, cliente, matrícula, VIN, módulo, técnico..." /></div><div className="panel">{orders.map(o => <div key={o.id} className="row clickable" onClick={() => { setSelected(o); setView("editor"); }}><b>{o.ot_number}</b><span>{o.client_name || "Sin cliente"}</span><span>{o.vehicle_plate || o.vehicle_vin}</span><span>{o.module_type}</span><span className="pill">{o.status}</span></div>)}</div></section>;
}

function Editor({ order, setSelected, saveOrder, deleteOrder, setView }) {
  const update = patch => setSelected({ ...order, ...patch });
  const toggleService = service => {
    const list = order.services || [];
    update({ services: list.includes(service) ? list.filter(s=>s!==service) : [...list, service] });
  };
  return <section><div className="head no-print"><h2>{order.ot_number}</h2><div className="actions"><button className="red" onClick={() => saveOrder(order)}><Save size={16}/> Guardar</button><button onClick={() => setView("clientCopy")}><Printer size={16}/> Copia cliente</button><button onClick={() => setView("warranty")}><ShieldCheck size={16}/> Garantía</button><button className="danger" onClick={() => deleteOrder(order)}><Trash2 size={16}/> Eliminar</button></div></div>
  <div className="grid2">
    <Box title="Orden" icon={<FileText/>}><Input label="Nº OT" value={order.ot_number} onChange={v=>update({ot_number:v})}/><Input label="Fecha entrada" type="date" value={order.date_in} onChange={v=>update({date_in:v})}/><Input label="Fecha salida" type="date" value={order.date_out} onChange={v=>update({date_out:v})}/><Select label="Estado" value={order.status} onChange={v=>update({status:v})} options={STATUS}/></Box>
    <Box title="Cliente" icon={<Users/>}><Input label="Cliente / Empresa" value={order.client_name} onChange={v=>update({client_name:v})}/><Input label="Teléfono / WhatsApp" value={order.client_phone} onChange={v=>update({client_phone:v})}/><Input label="Email" value={order.client_email} onChange={v=>update({client_email:v})}/><Select label="Tipo cliente" value={order.client_type} onChange={v=>update({client_type:v})} options={["Particular","Taller colaborador","Distribuidor"]}/></Box>
    <Box title="Vehículo" icon={<Car/>}><Input label="Marca" value={order.vehicle_brand} onChange={v=>update({vehicle_brand:v})}/><Input label="Modelo" value={order.vehicle_model} onChange={v=>update({vehicle_model:v})}/><Input label="Matrícula" value={order.vehicle_plate} onChange={v=>update({vehicle_plate:v})}/><Input label="VIN" value={order.vehicle_vin} onChange={v=>update({vehicle_vin:v})}/><Input label="Año" value={order.vehicle_year} onChange={v=>update({vehicle_year:v})}/></Box>
    <Box title="Módulo / Unidad" icon={<Cpu/>}><Input label="Tipo módulo / unidad" value={order.module_type} onChange={v=>update({module_type:v})}/><Input label="Referencia" value={order.module_ref} onChange={v=>update({module_ref:v})}/><Input label="Nº serie" value={order.module_serial} onChange={v=>update({module_serial:v})}/><Select label="Procedencia" value={order.module_source} onChange={v=>update({module_source:v})} options={["Aportado por cliente","Suministrado por AUTOKEYS REMAPS PRO"]}/></Box>
    <Box title="Técnicos manuales" icon={<Wrench/>}><Input label="Técnico responsable" value={order.technician_main} onChange={v=>update({technician_main:v})}/><Input label="Técnico auxiliar" value={order.technician_aux} onChange={v=>update({technician_aux:v})}/><Input label="Revisado por" value={order.reviewed_by} onChange={v=>update({reviewed_by:v})}/></Box>
    <Box title="Ingresos / Gastos" icon={<Euro/>}><Input label="Servicio cobrado (€)" type="number" value={order.income_service} onChange={v=>update({income_service:v})}/><Input label="Transporte cobrado (€)" type="number" value={order.income_transport} onChange={v=>update({income_transport:v})}/><Input label="Extras (€)" type="number" value={order.income_extra} onChange={v=>update({income_extra:v})}/><Input label="Descuento (€)" type="number" value={order.discount} onChange={v=>update({discount:v})}/><Input label="Gasto componentes (€)" type="number" value={order.expense_parts} onChange={v=>update({expense_parts:v})}/><Input label="Gasto módulo (€)" type="number" value={order.expense_module} onChange={v=>update({expense_module:v})}/><Input label="Gasto transporte (€)" type="number" value={order.expense_transport} onChange={v=>update({expense_transport:v})}/><Input label="Gasto material (€)" type="number" value={order.expense_material} onChange={v=>update({expense_material:v})}/><Input label="Gasto mano obra (€)" type="number" value={order.expense_labor} onChange={v=>update({expense_labor:v})}/><Input label="Otros gastos (€)" type="number" value={order.expense_other} onChange={v=>update({expense_other:v})}/><Select label="Forma de pago" value={order.payment_method} onChange={v=>update({payment_method:v})} options={PAYMENTS}/><label className="checkline"><input type="checkbox" checked={!!order.paid} onChange={e=>update({paid:e.target.checked})}/> Pagado</label><div className="totals">Ingresos: {totalIncome(order).toFixed(2)} € · Gastos: {totalExpenses(order).toFixed(2)} € · Beneficio: <b>{profit(order).toFixed(2)} €</b></div></Box>
  </div>
  <Box title="Servicios" icon={<KeyRound/>}><div className="services">{SERVICES.map(s => <button key={s} type="button" className={(order.services || []).includes(s) ? "selected" : ""} onClick={()=>toggleService(s)}>{s}</button>)}</div><Input label="Servicio realizado manual para copia cliente / garantía" value={order.service_manual} onChange={v=>update({service_manual:v})}/><Input label="Módulo o unidad intervenida manual para garantía" value={order.unit_manual} onChange={v=>update({unit_manual:v})}/></Box>
  <div className="grid2"><Textarea label="Descripción de avería" value={order.fault_description} onChange={v=>update({fault_description:v})}/><Textarea label="Diagnóstico técnico" value={order.diagnosis} onChange={v=>update({diagnosis:v})}/><Textarea label="Trabajo realizado" value={order.work_done} onChange={v=>update({work_done:v})}/><Textarea label="Componentes sustituidos" value={order.replaced_parts} onChange={v=>update({replaced_parts:v})}/><Textarea label="Pruebas realizadas" value={order.tests_done} onChange={v=>update({tests_done:v})}/><Textarea label="Observaciones internas" value={order.internal_notes} onChange={v=>update({internal_notes:v})}/><Textarea label="Observaciones cliente" value={order.client_notes} onChange={v=>update({client_notes:v})}/><Box title="Envío / Garantía" icon={<ShieldCheck/>}><Input label="Seguimiento entrada" value={order.tracking_in} onChange={v=>update({tracking_in:v})}/><Input label="Seguimiento salida" value={order.tracking_out} onChange={v=>update({tracking_out:v})}/><label className="checkline"><input type="checkbox" checked={!!order.warranty_applies} onChange={e=>update({warranty_applies:e.target.checked})}/> Garantía aplicada</label><Textarea label="Notas garantía" value={order.warranty_notes} onChange={v=>update({warranty_notes:v})}/></Box></div>
  </section>;
}

function Finance({ orders, setSelected, setView }) {
  const income = orders.reduce((a,o)=>a+totalIncome(o),0);
  const expenses = orders.reduce((a,o)=>a+totalExpenses(o),0);
  const byTech = Object.entries(orders.reduce((acc,o)=>{ const t = o.technician_main || "Sin técnico"; acc[t] = acc[t] || {count:0, income:0, profit:0}; acc[t].count++; acc[t].income += totalIncome(o); acc[t].profit += profit(o); return acc; },{}));
  return <section><h2>Gastos y beneficios</h2><div className="cards"><Card label="Ingresos totales" value={income.toFixed(2)+" €"}/><Card label="Gastos totales" value={expenses.toFixed(2)+" €"}/><Card label="Beneficio neto" value={(income-expenses).toFixed(2)+" €"}/><Card label="Pendiente cobro" value={orders.filter(o=>!o.paid).length}/></div><div className="panel"><h3>Beneficio por técnico</h3>{byTech.map(([tech,v]) => <div className="row" key={tech}><b>{tech}</b><span>OT: {v.count}</span><span>Facturación: {v.income.toFixed(2)} €</span><span>Beneficio: {v.profit.toFixed(2)} €</span><span></span></div>)}</div><div className="panel"><h3>Órdenes rentabilidad</h3>{orders.map(o => <div className="row clickable" key={o.id} onClick={()=>{setSelected(o);setView("editor");}}><b>{o.ot_number}</b><span>{o.client_name}</span><span>Ingresos: {totalIncome(o).toFixed(2)} €</span><span>Gastos: {totalExpenses(o).toFixed(2)} €</span><span className="pill">{profit(o).toFixed(2)} €</span></div>)}</div></section>;
}

function ClientCopy({ order }) {
  const whatsapp = makeWhatsApp(order);
  return <Printable><DocHeader title="INFORME DE SERVICIO AL CLIENTE" code={order.ot_number}/><div className="docGrid"><Info title="Orden" rows={[["Nº Orden",order.ot_number],["Fecha entrada",order.date_in],["Fecha entrega",order.date_out||"Pendiente"],["Estado",order.status]]}/><Info title="Cliente" rows={[["Cliente",order.client_name],["Teléfono",order.client_phone],["Email",order.client_email]]}/><Info title="Vehículo" rows={[["Marca / Modelo",`${order.vehicle_brand||""} ${order.vehicle_model||""}`],["Matrícula",order.vehicle_plate],["VIN",order.vehicle_vin]]}/><Info title="Servicio" rows={[["Servicio realizado",order.service_manual || (order.services||[]).join(", ")],["Módulo / Unidad",order.unit_manual || order.module_type],["Referencia",order.module_ref]]}/></div><h3>Resultado / observaciones</h3><p className="boxText">{order.client_notes || order.work_done || "Servicio realizado según orden de trabajo."}</p><div className="priceBox"><div><span>Importe del servicio</span><strong>{totalIncome(order).toFixed(2)} €</strong></div><div><span>Forma de pago</span><strong>{order.payment_method}</strong></div></div><h3>Garantía</h3><p>El presente servicio queda sujeto a las condiciones generales de garantía GAR-001 de AUTOKEYS REMAPS PRO.</p><DocFooter/><div className="no-print docActions"><button onClick={()=>window.print()}><Printer size={16}/> Imprimir / Guardar PDF</button><a className="button" href={whatsapp} target="_blank"><Send size={16}/> WhatsApp</a></div></Printable>;
}

function Warranty({ order }) {
  return <Printable><DocHeader title="GAR-001 · CONDICIONES GENERALES DE GARANTÍA" code={order.ot_number}/><div className="docGrid"><Info title="Datos del servicio" rows={[["Nº Orden",order.ot_number],["Fecha",order.date_out||order.date_in],["Cliente",order.client_name],["Servicio realizado",order.service_manual || (order.services||[]).join(", ")],["Módulo / Unidad intervenida",order.unit_manual || order.module_type],["Procedencia",order.module_source]]}/><Info title="Contacto" rows={[["Empresa","AUTOKEYS REMAPS PRO"],["Tel/WhatsApp","632 982 646"],["Correo","info@autokeyspro.es"]]}/></div><h3>Garantía del servicio</h3><p>AUTOKEYS REMAPS PRO garantiza exclusivamente la intervención técnica realizada sobre el servicio, módulo o unidad indicada en esta orden de trabajo.</p><h3>Verificación de garantía</h3><p>Cualquier incidencia deberá ser verificada por AUTOKEYS REMAPS PRO mediante la comprobación física del vehículo, módulo o unidad correspondiente.</p><h3>Exclusiones de garantía</h3><ul><li>Manipulación, apertura, reparación o modificación por terceros ajenos a AUTOKEYS REMAPS PRO.</li><li>Instalación incorrecta o realizada por personal no cualificado o no profesional del sector.</li><li>Daños por cortocircuitos, sobretensiones, humedad, golpes, conexión defectuosa o problemas eléctricos del vehículo.</li><li>Averías en otros sistemas electrónicos, mecánicos, red CAN, inmovilizador, cableado o unidades asociadas.</li><li>Diagnósticos o informes emitidos por terceros sin verificación por parte de AUTOKEYS REMAPS PRO.</li></ul><h3>Material aportado por el cliente</h3><p>Cuando el servicio sea realizado sobre módulos, centralitas, unidades electrónicas o cualquier otro material suministrado por el cliente, AUTOKEYS REMAPS PRO garantiza exclusivamente la intervención técnica efectuada sobre dicho material.</p><p>AUTOKEYS REMAPS PRO no será responsable del funcionamiento final del sistema, vehículo o conjunto electrónico cuando el material utilizado haya sido aportado por el cliente o por terceros ajenos a nuestra empresa.</p><p>AUTOKEYS REMAPS PRO únicamente asumirá responsabilidad sobre el correcto funcionamiento y garantía integral de los módulos, unidades o componentes suministrados directamente por nuestra empresa.</p><h3>Limitación de responsabilidad</h3><p>AUTOKEYS REMAPS PRO no asumirá responsabilidad por daños derivados de una instalación incorrecta, manipulaciones posteriores, modificaciones no autorizadas o fallos ajenos al trabajo realizado.</p><p>La aceptación, instalación o utilización del servicio implica la conformidad con las presentes condiciones.</p><DocFooter/><div className="no-print docActions"><button onClick={()=>window.print()}><Printer size={16}/> Imprimir / Guardar PDF</button></div></Printable>;
}

function makeWhatsApp(order) {
  const phone = String(order.client_phone || "").replace(/\D/g, "");
  const finalPhone = phone.startsWith("34") ? phone : "34" + phone;
  const text = `Hola, adjuntamos la documentación correspondiente a la Orden de Trabajo ${order.ot_number}.\n\nServicio: ${order.service_manual || (order.services||[]).join(", ")}\nImporte: ${totalIncome(order).toFixed(2)} €\n\nAUTOKEYS REMAPS PRO\nTel./WhatsApp: 632 982 646`;
  return `https://wa.me/${finalPhone}?text=${encodeURIComponent(text)}`;
}
function DocHeader({ title, code }) { return <div className="docHeader">{LOGO && <img src={LOGO}/>}<div><h1>AUTOKEYS REMAPS PRO</h1><h2>{title}</h2><p>{code}</p></div></div>; }
function DocFooter() { return <footer className="docFooter">AUTOKEYS REMAPS PRO · Tel/WhatsApp: 632 982 646 · info@autokeyspro.es</footer>; }
function Printable({ children }) { return <section className="printable">{children}</section>; }
function Info({ title, rows }) { return <div className="info"><h3>{title}</h3>{rows.map(([k,v])=><p key={k}><b>{k}:</b> <span>{v||"—"}</span></p>)}</div>; }
function Box({ title, icon, children }) { return <div className="box"><h3>{icon}{title}</h3>{children}</div>; }
function Input({ label, value, onChange, type="text" }) { return <label>{label}<input type={type} value={value ?? ""} onChange={e=>onChange(e.target.value)}/></label>; }
function Select({ label, value, onChange, options }) { return <label>{label}<select value={value ?? ""} onChange={e=>onChange(e.target.value)}>{options.map(o=><option key={o} value={o}>{o}</option>)}</select></label>; }
function Textarea({ label, value, onChange }) { return <label>{label}<textarea value={value ?? ""} onChange={e=>onChange(e.target.value)}/></label>; }

createRoot(document.getElementById("root")).render(<App/>);
